// src/components/Header.js
import React, { useState } from "react";
import { Link } from "gatsby";

const Header = () => {
  // State to track mobile menu open/close status
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  // Function to toggle the menu
  const toggleMenu = () => {
    setIsMenuOpen(!isMenuOpen);
  };

  return (
    <header className="bg-gray-900 text-white py-6">
      <div className="container mx-auto px-4 flex justify-between items-center">
        <h1 className="text-2xl font-bold">
          <Link to="/">Varad Blogs</Link>
        </h1>
        <nav className="hidden md:flex space-x-4">
          <Link to="#about" className="hover:text-gray-400">About</Link>
          <Link to="#projects" className="hover:text-gray-400">Projects</Link>
          <Link to="#contact" className="hover:text-gray-400">Contact</Link>
        </nav>
        {/* Mobile menu icon */}
        <div className="md:hidden">
          <button onClick={toggleMenu} className="text-gray-400 focus:outline-none">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 6h16M4 12h16M4 18h16" />
            </svg>
          </button>
        </div>
      </div>
      
      {/* Mobile Flyout Menu with Slide-in Transition */}
      <div
        className={`fixed top-0 left-0 h-full w-64 bg-gray-800 transform ${
          isMenuOpen ? "translate-x-0" : "-translate-x-full"
        } transition-transform duration-500 ease-in-out z-50`}
      >
        <button
          onClick={toggleMenu}
          className="text-white p-4 focus:outline-none absolute top-4 right-4"
        >
          ✕
        </button>
        <nav className="mt-16 space-y-4 px-4">
          <Link to="#about" className="block text-gray-300 hover:bg-gray-700 p-4 rounded">About</Link>
          <Link to="#projects" className="block text-gray-300 hover:bg-gray-700 p-4 rounded">Projects</Link>
          <Link to="#contact" className="block text-gray-300 hover:bg-gray-700 p-4 rounded">Contact</Link>
        </nav>
      </div>
    </header>
  );
};

export default Header;
